import au.com.dius.pact.consumer.dsl.*;
import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.*;

class PactMatcherGuide {

    @Test void pact_matchers_overview() {
        PactDslJsonBody body = new PactDslJsonBody()
            // TYPE matchers (flexible — checks type, not exact value):
            .stringType("paymentId","PAY-001")     // any String (example: PAY-001)
            .numberType("amountPaise",500000L)     // any Number (Long, Int, Double)
            .integerType("quantity",5)             // any Integer (not Float)
            .booleanType("active",true)            // any Boolean

            // EXACT VALUE matchers (brittle — breaks if value changes):
            // .stringValue("status","SUCCESS")    // must be exactly 'SUCCESS'

            // REGEX matcher (validates format):
            .stringMatcher("orderId","ORD-[0-9]+","ORD-12345")  // must match regex
            .stringMatcher("status","SUCCESS|FAILED|PENDING","SUCCESS")

            // ARRAY matchers:
            .minArrayLike("items",1,              // array with at least 1 item
                new PactDslJsonBody()
                    .stringType("itemId")
                    .numberType("price"))

            // OBJECT matchers:
            .object("metadata")
                .stringType("gateway","HDFC")
            .closeObject();

        // Verify our body has the expected fields (simplified):
        assertNotNull(body);
        System.out.println("PactDslJsonBody matchers configured correctly");
    }

    @Test void use_type_not_value_matchers() {
        // RULE: prefer type matchers for Pact
        // WHY: exact values make tests fragile
        //   stringValue('paymentId','PAY-001'): fails if server returns 'PAY-002'
        //   stringType('paymentId','PAY-001'):  passes if server returns any String
        // EXCEPTION: status codes, enum-like fields (regex matcher)
        //   stringMatcher('status','SUCCESS|FAILED|PENDING'): validates allowed values
        assertTrue(true);
        System.out.println("Type matchers: flexible. Regex matchers: for enums.");
    }
}

