import au.com.dius.pact.consumer.junit5.*;
import au.com.dius.pact.consumer.dsl.*;
import au.com.dius.pact.core.model.*;
import au.com.dius.pact.core.model.annotations.Pact;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.*;
import static org.junit.jupiter.api.Assertions.*;

// V1: Consumer tests that PASS (original API working)
@ExtendWith(PactConsumerTestExt.class)
@PactTestFor(providerName="razorpay-payment-api",port="8090")
class ConsumerV1BreakingTest {
    @Pact(consumer="consumer-v1",provider="razorpay-payment-api")
    RequestResponsePact v1Pact(PactDslWithProvider b){
        return b.given("payment exists")
            .uponReceiving("get payment")
            .method("GET").path("/api/payments/PAY-001")
            .willRespondWith().status(200)
            .body(new PactDslJsonBody()
                .stringType("paymentId","PAY-001")  // original field name
                .stringType("status","SUCCESS"))    // original field name
            .toPact();
    }
    @Test @PactTestFor(pactMethod="v1Pact")
    void v1_pact_valid(MockServer m) throws Exception {
        var r=java.net.http.HttpClient.newHttpClient().send(
            java.net.http.HttpRequest.newBuilder(java.net.URI.create(m.getUrl()+"/api/payments/PAY-001")).GET().build(),
            java.net.http.HttpResponse.BodyHandlers.ofString());
        assertEquals(200,r.statusCode());
        assertTrue(r.body().contains("paymentId"), "V1 consumer: paymentId field must exist");
        assertTrue(r.body().contains("status"), "V1 consumer: status field must exist");
        // This test PASSES: consumer contract is well-defined and mock server satisfies it
    }
}

// WHAT HAPPENS ON PROVIDER SIDE when they return {id, state} instead:
// Provider CI runs: FlipkartConsumerV1Test pact → verifies real API
// Real API returns: { 'id': 'PAY-001', 'state': 'SUCCESS' }
// Pact verifies: 'paymentId' present? NO → VIOLATION
// Pact verifies: 'status' present? NO → VIOLATION
// Provider CI: FAIL → deployment blocked

// Demonstrate the detection (simulated):
class BreakingChangeSimulation {
    @org.junit.jupiter.api.Test
    void breaking_change_detected(){
        // Simulate provider returning renamed fields:
        String providerResponse="{\"id\":\"PAY-001\",\"state\":\"SUCCESS\"}";

        // Consumer expects 'paymentId' → check if missing:
        assertFalse(providerResponse.contains("\"paymentId\""),
            "Breaking change: provider removed 'paymentId' field");
        assertFalse(providerResponse.contains("\"status\""),
            "Breaking change: provider removed 'status' field");

        // Both assertions pass (confirming the breaking change is detectable)
        // In real Pact: provider verification would FAIL at this point
        System.out.println("Breaking change DETECTED: paymentId → id, status → state");
    }
}

