import au.com.dius.pact.consumer.junit5.*;
import au.com.dius.pact.consumer.dsl.*;
import au.com.dius.pact.core.model.*;
import au.com.dius.pact.core.model.annotations.Pact;
import org.junit.jupiter.api.*;
import org.junit.jupiter.api.extension.*;
import static org.junit.jupiter.api.Assertions.*;

class M25T2States {
    static final String MERCHANT_EXISTS="merchant MRC-S exists";
    static final String PAYMENT_NOT_FOUND="payment PAY-X does not exist";
}

@ExtendWith(PactConsumerTestExt.class)
@PactTestFor(providerName="rzp-api-synth",port="8091")
class M25T2SuccessPact {
    @Pact(consumer="synth-consumer",provider="rzp-api-synth")
    RequestResponsePact p(PactDslWithProvider b){
        return b.given(M25T2States.MERCHANT_EXISTS)
            .uponReceiving("create payment")
            .method("POST").path("/api/payments")
            .body(new PactDslJsonBody().stringType("merchantId","MRC-S").numberType("amountPaise",100L))
            .willRespondWith().status(201)
            .body(new PactDslJsonBody()
                .stringType("paymentId","PAY-S1")
                .stringType("status","SUCCESS")
                .numberType("amountPaise",100L))
            .toPact();
    }
    @Test @PactTestFor(pactMethod="p")
    void successPact(MockServer m) throws Exception {
        var body=java.net.http.HttpRequest.BodyPublishers.ofString("{\"merchantId\":\"MRC-S\",\"amountPaise\":100}");
        var r=java.net.http.HttpClient.newHttpClient().send(java.net.http.HttpRequest.newBuilder(java.net.URI.create(m.getUrl()+"/api/payments")).POST(body).header("Content-Type","application/json").build(),java.net.http.HttpResponse.BodyHandlers.ofString());
        assertEquals(201,r.statusCode()); assertTrue(r.body().contains("paymentId")); assertTrue(r.body().contains("amountPaise"));
    }
}

@ExtendWith(PactConsumerTestExt.class)
@PactTestFor(providerName="rzp-api-synth",port="8092")
class M25T2ErrorPact {
    @Pact(consumer="synth-consumer",provider="rzp-api-synth")
    RequestResponsePact p(PactDslWithProvider b){
        return b.given(M25T2States.PAYMENT_NOT_FOUND)
            .uponReceiving("get missing payment")
            .method("GET").path("/api/payments/PAY-X")
            .willRespondWith().status(404)
            .body(new PactDslJsonBody().stringValue("error","PAYMENT_NOT_FOUND").stringType("message","not found"))
            .toPact();
    }
    @Test @PactTestFor(pactMethod="p")
    void errorPact(MockServer m) throws Exception {
        var r=java.net.http.HttpClient.newHttpClient().send(java.net.http.HttpRequest.newBuilder(java.net.URI.create(m.getUrl()+"/api/payments/PAY-X")).GET().build(),java.net.http.HttpResponse.BodyHandlers.ofString());
        assertEquals(404,r.statusCode()); assertTrue(r.body().contains("PAYMENT_NOT_FOUND"));
    }
}

